  ('dietitian-moex-10424', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '程先生健康檢查後的總膽固醇值為170 mg/dL，高密度脂蛋白膽固醇值為40 mg/dL，三酸甘油酯值為100 mg/dL，請問程先生的 低密度脂蛋白膽固醇值為多少mg/dL？', '["30", "70", "110", "130"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
